use std::collections::BTreeSet;
fn main() {
    let mut ri = ReadIn::new();
    let tp = ri.int2();
    let n = tp.0 as usize;
    let m = tp.1;
    let mut it = ri.ints();
    let mut num = Vec::new();
    for _ in 0..n {
        num.push(it.next().unwrap());
    }
    if n == 1 {
        println!("{}", num[0] % m);
        return ;
    }
    let fst = num[0..n/2].to_vec();
    let snd = num[n/2..n].to_vec();
    let s1 = explore(fst,m);
    let s2 = explore(snd,m);
    let mut it3 = s1.iter();
    let mut it4 = s2.iter();
    let x = it3.next_back().unwrap();
    let y = it4.next_back().unwrap();
    let mut ans = (*x + *y) % m;
    let mut it1 = s1.iter();
    loop {
        match it1.next() {
            Some(v1) => {
                match s2.range(0..m-v1).next_back() {
                    Some(v2) => {
                        if v1 + v2 > ans {
                            ans = v1 + v2;
                        }
                    },
                    None => continue,
                }
            },
            None => break,
        }
    }
    println!("{}", ans);
}

fn explore(v:Vec<i32>, m:i32) -> BTreeSet<i32> {
    let n = v.len();
    let mut st = BTreeSet::new();
    for msk in 0..1<<n {
        let mut s = 0;
        for i in 0..n {
            if (msk & (1<<i)) > 0 {
                s = (s + v[i]) % m;
            }
        }
        st.insert(s);
    }
    st
}

use std::iter::Map;
use std::str::SplitWhitespace;
use std::io::stdin;
use std::mem::forget;

pub struct ReadIn(pub String);

impl ReadIn {
    pub fn new() -> ReadIn {
        ReadIn(String::new())
    }
    fn read_i32(s: &str) -> i32 {
        s.parse().unwrap()
    }
    pub fn read_line(&mut self) {
        self.0.clear();
        forget(stdin().read_line(&mut self.0));
    }
    pub fn ints(&mut self) -> Map<SplitWhitespace, fn(&str) -> i32> {
        self.read_line();
        self.0.split_whitespace().map(ReadIn::read_i32)
    }
    pub fn int(&mut self) -> i32 {
        self.ints().next().unwrap()
    }
    pub fn int2(&mut self) -> (i32, i32) {
        let mut it = self.ints();
        (it.next().unwrap(), it.next().unwrap())
    }
}
